/*
 * MathML-first, LaTeX-fallback for pages generated by the pelican_typst
 * plugin. Detects whether the browser actually renders MathML (rather
 * than just not-crashing on unknown tags); if not, hides the <math>
 * element and shows the LaTeX source instead, optionally re-rendering
 * it with KaTeX or MathJax if either is present on the page.
 *
 * Include this file on any page that may contain `.typst-math` spans,
 * e.g. via Pelican's EXTRA_JS_FILES / STATIC_PATHS settings.
 */
(function () {
  "use strict";

  function mathmlSupported() {
    try {
      var ns = "http://www.w3.org/1998/Math/MathML";
      var math = document.createElementNS(ns, "math");
      var mspace = document.createElementNS(ns, "mspace");
      mspace.setAttribute("width", "23px");
      math.appendChild(mspace);
      math.style.visibility = "hidden";
      math.style.position = "absolute";
      document.body.appendChild(math);
      var rect = mspace.getBoundingClientRect();
      document.body.removeChild(math);
      return Math.abs(rect.width - 23) < 1;
    } catch (e) {
      return false;
    }
  }

  function renderFallback(fallback, displayMode) {
    var raw = fallback.textContent;
    var tex = raw.replace(/^\\\(|\\\)$/g, "").replace(/^\\\[|\\\]$/g, "");

    if (window.katex && typeof window.katex.render === "function") {
      try {
        window.katex.render(tex, fallback, {
          displayMode: displayMode,
          throwOnError: false,
        });
        return;
      } catch (e) {
        /* fall through to plain text */
      }
    }
    if (window.MathJax && typeof window.MathJax.typesetPromise === "function") {
      window.MathJax.typesetPromise([fallback]);
      return;
    }
    // No renderer available -- leave the raw LaTeX source visible.
  }

  function init() {
    var forced = window.FORCE_LATEX_FALLBACK === true;
    if (!forced && mathmlSupported()) return;
    var nodes = document.querySelectorAll(".typst-math");
    nodes.forEach(function (node) {
      var mathEl = node.querySelector("math");
      var fallback = node.querySelector(".typst-math-fallback");
      if (mathEl) mathEl.style.display = "none";
      if (!fallback) return;
      fallback.hidden = false;
      renderFallback(fallback, node.dataset.display === "block");
    });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    init();
  }
})();
